// Configure your target job boards here
const jobBoards = [
  {
    name: 'LinkedIn',
    searchUrl: 'https://www.linkedin.com/jobs/search/?keywords=AI+consultant+OR+%22AI+implementation%22+OR+%22AI+automation%22&f_TPR=r86400',
    keywords: ['AI consultant', 'AI implementation', 'AI automation', 'fractional AI']
  },
  {
    name: 'Indeed',
    searchUrl: 'https://www.indeed.com/jobs?q=AI+consultant+OR+AI+automation&sort=date&fromage=1',
    keywords: ['AI consultant', 'AI automation']
  }
];

return jobBoards.map(board => ({ json: board }));

// Parse Airtop response and filter relevant jobs
const response = $input.first().json;
const jobs = response.result?.jobs || response.jobs || response.data || [];

// Filter for relevance
const keywords = ['AI', 'automation', 'consultant', 'implementation', 'fractional', 'ChatGPT', 'Claude', 'LLM'];
const relevant = jobs.filter(job => {
  const text = `${job.title} ${job.description}`.toLowerCase();
  return keywords.some(kw => text.includes(kw.toLowerCase()));
});

return relevant.map(job => ({ json: {
  title: job.title || 'Unknown Role',
  company: job.company || 'Unknown',
  location: job.location || '',
  postedDate: job.posted_date || new Date().toISOString().split('T')[0],
  jobUrl: job.job_url || job.url || '',
  description: (job.description || '').substring(0, 500),
}}));
